package org.example.service;
import org.example.model.dto.NotificationDto; import org.example.model.entity.*; import org.example.model.enums.*; import org.example.repository.*; import org.junit.jupiter.api.Test; import org.junit.jupiter.api.extension.ExtendWith; import org.mockito.*; import org.mockito.junit.jupiter.MockitoExtension; import java.util.*; import static org.junit.jupiter.api.Assertions.*; import static org.mockito.ArgumentMatchers.any; import static org.mockito.Mockito.*;
@ExtendWith(MockitoExtension.class) class NotificationServiceTest { @Mock NotificationRepository notificationRepository; @Mock UserRepository userRepository; @InjectMocks NotificationService service; @Test void shouldCreateNotification(){ User user=new User(); user.setId(1L); NotificationDto dto=new NotificationDto(); dto.setTitle("Напоминание"); dto.setMessage("Завтра пара по Spring"); dto.setChannel(NotificationChannel.EMAIL); dto.setRecipientId(1L); Notification saved=new Notification(); saved.setId(10L); saved.setTitle(dto.getTitle()); saved.setChannel(dto.getChannel()); saved.setStatus(NotificationStatus.CREATED); saved.setRecipient(user); when(userRepository.findById(1L)).thenReturn(Optional.of(user)); when(notificationRepository.save(any(Notification.class))).thenReturn(saved); Notification result=service.createNotification(dto); assertNotNull(result); assertEquals(10L,result.getId()); assertEquals(NotificationChannel.EMAIL,result.getChannel()); verify(notificationRepository,times(1)).save(any(Notification.class)); } @Test void shouldThrowExceptionWhenRecipientNotFound(){ NotificationDto dto=new NotificationDto(); dto.setTitle("Test"); dto.setMessage("Msg"); dto.setChannel(NotificationChannel.EMAIL); dto.setRecipientId(99L); when(userRepository.findById(99L)).thenReturn(Optional.empty()); assertThrows(IllegalArgumentException.class,()->service.createNotification(dto)); verify(notificationRepository,never()).save(any(Notification.class)); } }
